54	const CURSE_SURCHARGE_RATE = 0.5;
55	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
56	const HIGH_ENCHANTMENT_THRESHOLD = 5;
57	
58	const itemCurseSurcharge = (item: Item): number =>
59	  item.cursed === true ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
60	
61	const itemHighEnchantmentSurcharge = (item: Item): number => {
62	  const ench = item.enchantment;
63	  return typeof ench === "number" && ench >= HIGH_ENCHANTMENT_THRESHOLD
64	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
65	    : 0;
66	};
67	
68	const itemSpecificSurchargesSum = (items: Item[]): number =>
69	  items.reduce(
70	    (sum, item) =>
71	      sum + itemCurseSurcharge(item) + itemHighEnchantmentSurcharge(item),
72	    0,
73	  );
74	
75	const LOYALTY_DISCOUNT_RATE = 0.2;
76	const LOYALTY_YEARS_THRESHOLD = 2;
77	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
78	
79	const loyaltyDiscount = (baseSum: number, yearsWithMHPCO: number): number =>
80	  yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? baseSum * LOYALTY_DISCOUNT_RATE : 0;
81	
82	const followUpDiscount = (baseSum: number, priorQuoteCount: number): number =>
83	  priorQuoteCount > 0 ? baseSum * FOLLOW_UP_DISCOUNT_RATE : 0;
84	
85	const quotePremium = (
86	  items: Item[],
87	  customer: { yearsWithMHPCO: number },
88	  priorQuoteCount: number,
89	): number => {
90	  const baseSum = itemsBaseSum(items);
91	  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
92	  const itemSurcharges = itemSpecificSurchargesSum(items);
93	  const loyalty = loyaltyDiscount(baseSum, customer.yearsWithMHPCO);
94	  const followUp = followUpDiscount(baseSum, priorQuoteCount);
95	  return Math.ceil(
96	    baseSum + itemSurcharges - loyalty - followUp + firstInsuranceSurcharge + PROCESSING_FEE,
97	  );
98	};
